_KnownPythonTypes = typing.Type[typing.Union[
    str, float, bool, bytes, int, dict, UUID, Decimal, datetime, date, time,
    timedelta, IPv4Address, IPv6Address,
]]
class OpenApiTypes(enum.Enum):
    """
    Basic types known to the OpenAPI specification or at least common format extension of it.
    - Use ``BYTE`` for base64-encoded data wrapped in a string
    - Use ``BINARY`` for raw binary data
    - Use ``OBJECT`` for arbitrary free-form object (usually a :py:class:`dict`)
    """
    NUMBER = enum.auto()
    FLOAT = enum.auto()
    DOUBLE = enum.auto()
    BOOL = enum.auto()
    STR = enum.auto()
    BYTE = enum.auto()
    BINARY = enum.auto()
    PASSWORD = enum.auto()
    INT = enum.auto()
    INT32 = enum.auto()
    INT64 = enum.auto()
    UUID = enum.auto()
    URI = enum.auto()
    URI_REF = enum.auto()
    URI_TPL = enum.auto()
    IRI = enum.auto()
    IRI_REF = enum.auto()
    IP4 = enum.auto()
    IP6 = enum.auto()
    HOSTNAME = enum.auto()
    IDN_HOSTNAME = enum.auto()
    DECIMAL = enum.auto()
    DATETIME = enum.auto()
    DATE = enum.auto()
    TIME = enum.auto()
    DURATION = enum.auto()
    EMAIL = enum.auto()
    IDN_EMAIL = enum.auto()
    JSON_PTR = enum.auto()
    JSON_PTR_REL = enum.auto()
    REGEX = enum.auto()
    OBJECT = enum.auto()
    NONE = enum.auto()
    ANY = enum.auto()
